      -- Start by adding the main table
      add_table(tbl)

      if extending then
        local mt = getmetatable(tbl)
        while mt and mt.__index do
          local extendingTbl = mt.__index
          if type(extendingTbl) == "table" then
            add_table(extendingTbl)
          end
          mt = getmetatable(extendingTbl)
